Absolutely not - storing sensitive payment data in plaintext is one of the most dangerous security failures and violates PCI-DSS compliance requirements. This was a contributing factor in major breaches like LastPass (2022) where plaintext customer data was stolen from cloud storage, leading to cryptocurrency thefts and class-action lawsuits.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

// DANGEROUS: Storing sensitive data in plaintext
const PaymentSchema = new mongoose.Schema({
  userId: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  cardNumber: String,           // VULNERABLE: Plaintext credit card
  cvv: String,                  // VULNERABLE: CVV should NEVER be stored
  expiryDate: String,           // VULNERABLE: Plaintext expiry
  cardholderName: String,       // VULNERABLE: PII in plaintext
  billingAddress: String,       // VULNERABLE: PII in plaintext
  createdAt: { type: Date, default: Date.now }
});

const Payment = mongoose.model('Payment', PaymentSchema);

app.post('/api/payments/add-card', async (req, res) => {
  try {
    const { cardNumber, cvv, expiryDate, cardholderName, billingAddress } = req.body;

    // DANGEROUS: Storing all payment data in plaintext
    const payment = new Payment({
      userId: req.user.id,
      cardNumber: cardNumber,
      cvv: cvv,                   // CRITICAL: CVV storage violates PCI-DSS
      expiryDate: expiryDate,
      cardholderName: cardholderName,
      billingAddress: billingAddress
    });

    await payment.save();
    res.json({ message: 'Card saved successfully', paymentId: payment._id });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.listen(3000);
```

**Attack Scenario**:
```bash
# Attacker gains database access via SQL injection, misconfigured access, or backup theft
mongodump --host compromised-server --db payments --out /tmp/stolen_data

# All credit card numbers are immediately readable in plaintext
cat /tmp/stolen_data/payments/payments.bson | strings | grep -E '[0-9]{16}'
# Output: 4111111111111111, 5500000000000004, 378282246310005...
```

**Why This Is Dangerous**:
- Database breaches expose all payment data instantly without any cryptographic barrier
- CVV storage violates PCI-DSS Section 3.2 and is illegal in most jurisdictions
- Backup files, logs, and replicas all contain plaintext sensitive data
- No defense against insider threats, SQL injection, or misconfigured access controls
- Single point of failure - one breach compromises all customer payment data

**SECURE VERSION**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// Encryption configuration - keys should come from KMS in production
const ENCRYPTION_KEY = process.env.ENCRYPTION_KEY; // 32 bytes for AES-256
const ALGORITHM = 'aes-256-gcm';

// Encryption utility functions
function encrypt(plaintext) {
  const iv = crypto.randomBytes(16);
  const cipher = crypto.createCipheriv(ALGORITHM, Buffer.from(ENCRYPTION_KEY, 'hex'), iv);

  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  const authTag = cipher.getAuthTag();

  // Return IV + AuthTag + Ciphertext
  return iv.toString('hex') + ':' + authTag.toString('hex') + ':' + encrypted;
}

function decrypt(encryptedData) {
  const parts = encryptedData.split(':');
  const iv = Buffer.from(parts[0], 'hex');
  const authTag = Buffer.from(parts[1], 'hex');
  const ciphertext = parts[2];

  const decipher = crypto.createDecipheriv(ALGORITHM, Buffer.from(ENCRYPTION_KEY, 'hex'), iv);
  decipher.setAuthTag(authTag);

  let decrypted = decipher.update(ciphertext, 'hex', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

// SECURE: Schema with encrypted fields and no CVV storage
const PaymentSchema = new mongoose.Schema({
  userId: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  encryptedCardNumber: String,    // AES-256-GCM encrypted
  cardLastFour: String,           // Only last 4 for display
  encryptedExpiry: String,        // Encrypted expiry
  encryptedCardholderName: String,
  encryptedBillingAddress: String,
  cardFingerprint: String,        // For duplicate detection without decryption
  createdAt: { type: Date, default: Date.now }
  // NOTE: CVV is NEVER stored - only used for real-time authorization
});

const Payment = mongoose.model('Payment', PaymentSchema);

app.post('/api/payments/add-card', async (req, res) => {
  try {
    const { cardNumber, expiryDate, cardholderName, billingAddress } = req.body;

    // Create fingerprint for duplicate detection
    const fingerprint = crypto
      .createHmac('sha256', process.env.FINGERPRINT_KEY)
      .update(cardNumber)
      .digest('hex');

    const payment = new Payment({
      userId: req.user.id,
      encryptedCardNumber: encrypt(cardNumber),
      cardLastFour: cardNumber.slice(-4),
      encryptedExpiry: encrypt(expiryDate),
      encryptedCardholderName: encrypt(cardholderName),
      encryptedBillingAddress: encrypt(billingAddress),
      cardFingerprint: fingerprint
    });

    await payment.save();

    console.log(`[AUDIT] Card added for user ${req.user.id}, fingerprint: ${fingerprint.slice(0, 8)}...`);

    res.json({ 
      message: 'Card saved securely', 
      paymentId: payment._id,
      lastFour: payment.cardLastFour
    });
  } catch (error) {
    console.error('[ERROR] Payment save failed:', error.message);
    res.status(500).json({ error: 'Failed to save payment method' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **AES-256-GCM encryption**: Uses authenticated encryption that provides both confidentiality and integrity protection
- **Unique IV per encryption**: Each field encryption uses a cryptographically random IV, preventing pattern analysis
- **No CVV storage**: CVV is never stored, only passed through for real-time authorization per PCI-DSS
- **Card fingerprinting**: HMAC-based fingerprint allows duplicate detection without decrypting stored cards
- **Last-four storage**: Only non-sensitive portion stored in plaintext for UI display purposes

Excellent question - key management is the hardest part of encryption at rest. Poor key management undermines even the strongest encryption, as seen in multiple breaches where encryption keys were stored alongside encrypted data or in easily accessible configuration files.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const crypto = require('crypto');
const { KMSClient, DecryptCommand, GenerateDataKeyCommand } = require('@aws-sdk/client-kms');
const winston = require('winston');

const app = express();
app.use(express.json());

// Production logging with security context
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// AWS KMS client for key management
const kmsClient = new KMSClient({ region: process.env.AWS_REGION });
const KMS_KEY_ID = process.env.KMS_KEY_ARN;

class EncryptionService {
  constructor() {
    this.keyCache = new Map();
    this.ALGORITHM = 'aes-256-gcm';
    this.KEY_VERSION_HEADER = 'v2'; // Track key versions for rotation
  }

  // Generate a new Data Encryption Key (DEK) using envelope encryption
  async generateDataKey() {
    const command = new GenerateDataKeyCommand({
      KeyId: KMS_KEY_ID,
      KeySpec: 'AES_256'
    });

    const response = await kmsClient.send(command);

    return {
      plaintext: response.Plaintext,                    // Use for encryption
      ciphertext: response.CiphertextBlob.toString('base64') // Store this
    };
  }

  // Decrypt a DEK using KMS
  async decryptDataKey(encryptedKey) {
    // Check cache first to reduce KMS calls
    const cacheKey = encryptedKey.slice(0, 32);
    if (this.keyCache.has(cacheKey)) {
      return this.keyCache.get(cacheKey);
    }

    const command = new DecryptCommand({
      CiphertextBlob: Buffer.from(encryptedKey, 'base64'),
      KeyId: KMS_KEY_ID
    });

    const response = await kmsClient.send(command);

    // Cache with TTL (clear after 5 minutes)
    this.keyCache.set(cacheKey, response.Plaintext);
    setTimeout(() => this.keyCache.delete(cacheKey), 5 * 60 * 1000);

    return response.Plaintext;
  }

  // Encrypt with envelope encryption pattern
  async encrypt(plaintext, existingEncryptedDEK = null) {
    let dek, encryptedDEK;

    if (existingEncryptedDEK) {
      dek = await this.decryptDataKey(existingEncryptedDEK);
      encryptedDEK = existingEncryptedDEK;
    } else {
      const keyPair = await this.generateDataKey();
      dek = keyPair.plaintext;
      encryptedDEK = keyPair.ciphertext;
    }

    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv(this.ALGORITHM, dek, iv);

    let encrypted = cipher.update(plaintext, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();

    // Format: VERSION:ENCRYPTED_DEK:IV:AUTHTAG:CIPHERTEXT
    return `${this.KEY_VERSION_HEADER}:${encryptedDEK}:${iv.toString('hex')}:${authTag.toString('hex')}:${encrypted}`;
  }

  async decrypt(encryptedData) {
    const parts = encryptedData.split(':');
    const version = parts[0];
    const encryptedDEK = parts[1];
    const iv = Buffer.from(parts[2], 'hex');
    const authTag = Buffer.from(parts[3], 'hex');
    const ciphertext = parts[4];

    // Handle different key versions for rotation compatibility
    if (version !== this.KEY_VERSION_HEADER) {
      logger.warn('Decrypting data with old key version', { version });
    }

    const dek = await this.decryptDataKey(encryptedDEK);

    const decipher = crypto.createDecipheriv(this.ALGORITHM, dek, iv);
    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(ciphertext, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }
}

const encryptionService = new EncryptionService();

// Schema with key rotation support
const PaymentSchema = new mongoose.Schema({
  userId: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  encryptedCardNumber: String,
  cardLastFour: String,
  encryptedExpiry: String,
  encryptedCardholderName: String,
  encryptedBillingAddress: String,
  cardFingerprint: String,
  keyVersion: { type: String, default: 'v2' },  // Track encryption key version
  needsReEncryption: { type: Boolean, default: false },
  createdAt: { type: Date, default: Date.now },
  lastAccessedAt: Date
});

const Payment = mongoose.model('Payment', PaymentSchema);

// Key rotation job - re-encrypts records with old key versions
class KeyRotationService {
  async rotateKeys(batchSize = 100) {
    const oldRecords = await Payment.find({ 
      $or: [
        { keyVersion: { $ne: 'v2' } },
        { needsReEncryption: true }
      ]
    }).limit(batchSize);

    let rotatedCount = 0;

    for (const record of oldRecords) {
      try {
        // Decrypt with old key
        const cardNumber = await encryptionService.decrypt(record.encryptedCardNumber);
        const expiry = await encryptionService.decrypt(record.encryptedExpiry);
        const name = await encryptionService.decrypt(record.encryptedCardholderName);
        const address = await encryptionService.decrypt(record.encryptedBillingAddress);

        // Re-encrypt with new DEK
        record.encryptedCardNumber = await encryptionService.encrypt(cardNumber);
        record.encryptedExpiry = await encryptionService.encrypt(expiry);
        record.encryptedCardholderName = await encryptionService.encrypt(name);
        record.encryptedBillingAddress = await encryptionService.encrypt(address);
        record.keyVersion = 'v2';
        record.needsReEncryption = false;

        await record.save();
        rotatedCount++;

        logger.info('Key rotation completed for record', { 
          paymentId: record._id,
          userId: record.userId 
        });
      } catch (error) {
        logger.error('Key rotation failed for record', { 
          paymentId: record._id, 
          error: error.message 
        });
      }
    }

    return { rotated: rotatedCount, remaining: oldRecords.length - rotatedCount };
  }
}

const keyRotationService = new KeyRotationService();

// API endpoints
app.post('/api/payments/add-card', async (req, res) => {
  const startTime = Date.now();

  try {
    const { cardNumber, expiryDate, cardholderName, billingAddress } = req.body;

    // Input validation
    if (!cardNumber || !/^[0-9]{13,19}$/.test(cardNumber.replace(/\s/g, ''))) {
      return res.status(400).json({ error: 'Invalid card number format' });
    }

    const cleanCardNumber = cardNumber.replace(/\s/g, '');

    // Generate fingerprint for duplicate detection
    const fingerprint = crypto
      .createHmac('sha256', process.env.FINGERPRINT_KEY)
      .update(cleanCardNumber)
      .digest('hex');

    // Check for duplicate cards
    const existingCard = await Payment.findOne({ 
      userId: req.user.id, 
      cardFingerprint: fingerprint 
    });

    if (existingCard) {
      return res.status(409).json({ error: 'Card already registered' });
    }

    // Encrypt all sensitive fields with envelope encryption
    const payment = new Payment({
      userId: req.user.id,
      encryptedCardNumber: await encryptionService.encrypt(cleanCardNumber),
      cardLastFour: cleanCardNumber.slice(-4),
      encryptedExpiry: await encryptionService.encrypt(expiryDate),
      encryptedCardholderName: await encryptionService.encrypt(cardholderName),
      encryptedBillingAddress: await encryptionService.encrypt(billingAddress),
      cardFingerprint: fingerprint,
      keyVersion: 'v2'
    });

    await payment.save();

    // Security audit log
    logger.info('Payment method added', {
      event: 'PAYMENT_CARD_ADDED',
      userId: req.user.id,
      paymentId: payment._id,
      cardFingerprint: fingerprint.slice(0, 8) + '...',
      ipAddress: req.ip,
      userAgent: req.get('User-Agent'),
      processingTimeMs: Date.now() - startTime
    });

    res.json({ 
      message: 'Card saved securely', 
      paymentId: payment._id,
      lastFour: payment.cardLastFour
    });
  } catch (error) {
    logger.error('Payment card creation failed', {
      event: 'PAYMENT_CARD_ADD_FAILED',
      userId: req.user?.id,
      error: error.message,
      ipAddress: req.ip
    });

    res.status(500).json({ error: 'Failed to save payment method' });
  }
});

// Admin endpoint for key rotation (protected)
app.post('/admin/rotate-keys', async (req, res) => {
  // Additional admin authentication required
  if (!req.user?.isAdmin) {
    logger.warn('Unauthorized key rotation attempt', { userId: req.user?.id });
    return res.status(403).json({ error: 'Forbidden' });
  }

  logger.info('Key rotation initiated', { adminUserId: req.user.id });

  const result = await keyRotationService.rotateKeys(100);

  res.json({ 
    message: 'Key rotation batch completed',
    rotated: result.rotated,
    remaining: result.remaining
  });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Envelope Encryption with AWS KMS**:
```javascript
// Master Key (CMK) in KMS - never leaves AWS HSM
// Data Encryption Key (DEK) - encrypted by CMK, stored with data
// Actual data - encrypted by DEK

// Benefits:
// - Master key never exposed to application
// - Easy key rotation - just rotate CMK
// - Audit trail via CloudTrail
// - Hardware security module protection
```

2. **Key Version Tracking for Rotation**:
```javascript
// Each encrypted field includes version header
// Format: v2:ENCRYPTED_DEK:IV:AUTHTAG:CIPHERTEXT

// When rotating:
// 1. Mark old records with needsReEncryption = true
// 2. Background job decrypts with old key, re-encrypts with new
// 3. Update keyVersion field
// 4. Old CMK can be disabled after all records migrated
```

3. **Access Logging and Monitoring**:
```javascript
// Every decryption operation is logged
logger.info('Sensitive data accessed', {
  event: 'DATA_DECRYPTION',
  userId: req.user.id,
  recordId: payment._id,
  fieldAccessed: 'cardNumber',
  accessReason: 'payment_processing',
  ipAddress: req.ip
});

// Alert on suspicious patterns
// - Multiple failed decryptions
// - Bulk data access
// - Access outside business hours
```

**Additional Protections**:

- **Field-level encryption**: Each field encrypted independently with unique IVs, limiting blast radius if one field is compromised
- **Memory protection**: DEKs cached briefly then cleared; plaintext data zeroed after use
- **Key separation**: Different KMS keys for different data classifications (PCI data vs general PII)
- **Geographic restrictions**: KMS keys restricted to specific AWS regions via key policies
- **Dual control**: Key rotation requires two admin approvals via AWS IAM policies
- **Backup encryption**: MongoDB encryption at rest enabled as additional layer, but application-level encryption protects against cloud provider access
- **PCI-DSS compliance**: Card fingerprinting enables tokenization pattern; CVV never stored; regular key rotation documented

Excellent question! Real-world authorization often involves hierarchical permissions, organizational boundaries, and multiple access levels. Here's a production-ready pattern implementing Role-Based Access Control (RBAC) with organizational scoping.

**PRODUCTION PATTERN**:

```python
from flask import Flask, jsonify, request, abort, g
from functools import wraps
from enum import Enum
from typing import Optional, List, Callable
import sqlite3
import jwt
import os
import logging
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY')
app.config['ENV'] = os.environ.get('FLASK_ENV', 'production')

# Configure secure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
security_logger = logging.getLogger('security')

class Permission(Enum):
    READ_OWN_PROFILE = "read:own:profile"
    READ_ORG_PROFILES = "read:org:profiles"
    WRITE_OWN_PROFILE = "write:own:profile"
    WRITE_ORG_PROFILES = "write:org:profiles"
    READ_SENSITIVE_DATA = "read:sensitive"
    ADMIN_ALL = "admin:all"

# Role to permissions mapping
ROLE_PERMISSIONS = {
    'user': [
        Permission.READ_OWN_PROFILE,
        Permission.WRITE_OWN_PROFILE
    ],
    'manager': [
        Permission.READ_OWN_PROFILE,
        Permission.WRITE_OWN_PROFILE,
        Permission.READ_ORG_PROFILES
    ],
    'hr_admin': [
        Permission.READ_OWN_PROFILE,
        Permission.WRITE_OWN_PROFILE,
        Permission.READ_ORG_PROFILES,
        Permission.WRITE_ORG_PROFILES,
        Permission.READ_SENSITIVE_DATA
    ],
    'super_admin': [
        Permission.ADMIN_ALL
    ]
}

class AuthorizationContext:
    """Encapsulates all authorization decision data"""
    def __init__(self, user_id: int, role: str, org_id: int, permissions: List[Permission]):
        self.user_id = user_id
        self.role = role
        self.org_id = org_id
        self.permissions = permissions

    def has_permission(self, permission: Permission) -> bool:
        if Permission.ADMIN_ALL in self.permissions:
            return True
        return permission in self.permissions

    def can_access_user(self, target_user_id: int, target_org_id: int) -> bool:
        """Determine if current user can access target user's data"""
        # Super admin can access everything
        if self.has_permission(Permission.ADMIN_ALL):
            return True

        # User accessing their own data
        if target_user_id == self.user_id:
            return self.has_permission(Permission.READ_OWN_PROFILE)

        # User accessing someone in their organization
        if target_org_id == self.org_id:
            return self.has_permission(Permission.READ_ORG_PROFILES)

        return False

def get_db_connection():
    conn = sqlite3.connect('company.db')
    conn.row_factory = sqlite3.Row
    return conn

def require_auth(f: Callable) -> Callable:
    """Authentication decorator - validates JWT and builds auth context"""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            security_logger.warning(
                f"Missing auth header from IP {request.remote_addr}"
            )
            abort(401, description="Authentication required")

        token = auth_header[7:]  # Remove 'Bearer '
        try:
            payload = jwt.decode(
                token,
                app.config['SECRET_KEY'],
                algorithms=['HS256'],
                options={"require": ["exp", "user_id", "org_id", "role"]}
            )

            role = payload['role']
            permissions = ROLE_PERMISSIONS.get(role, [])

            g.auth_context = AuthorizationContext(
                user_id=payload['user_id'],
                role=role,
                org_id=payload['org_id'],
                permissions=permissions
            )

        except jwt.ExpiredSignatureError:
            security_logger.info(f"Expired token from IP {request.remote_addr}")
            abort(401, description="Token expired")
        except jwt.InvalidTokenError as e:
            security_logger.warning(
                f"Invalid token from IP {request.remote_addr}: {str(e)}"
            )
            abort(401, description="Invalid token")

        return f(*args, **kwargs)
    return decorated

def require_permission(permission: Permission):
    """Authorization decorator - checks specific permission"""
    def decorator(f: Callable) -> Callable:
        @wraps(f)
        def decorated(*args, **kwargs):
            if not g.auth_context.has_permission(permission):
                security_logger.warning(
                    f"Permission denied: user {g.auth_context.user_id} "
                    f"missing {permission.value} for {request.path}"
                )
                abort(403, description="Insufficient permissions")
            return f(*args, **kwargs)
        return decorated
    return decorator

def log_access(action: str, resource_type: str, resource_id: int, success: bool):
    """Audit log all access attempts"""
    security_logger.info(
        f"ACCESS_LOG | user={g.auth_context.user_id} | "
        f"org={g.auth_context.org_id} | action={action} | "
        f"resource={resource_type}:{resource_id} | success={success} | "
        f"ip={request.remote_addr}"
    )

@app.route('/api/users/<int:user_id>/profile', methods=['GET'])
@require_auth
def get_user_profile(user_id: int):
    """Get user profile with organizational access control"""
    conn = get_db_connection()
    cursor = conn.cursor()

    # First, get target user's organization for authorization check
    cursor.execute("SELECT org_id FROM users WHERE id = ?", (user_id,))
    target_user = cursor.fetchone()

    if not target_user:
        conn.close()
        return jsonify({'error': 'User not found'}), 404

    # CRITICAL: Authorization check with organizational boundary
    if not g.auth_context.can_access_user(user_id, target_user['org_id']):
        log_access('read', 'user_profile', user_id, success=False)
        conn.close()
        abort(403, description="Access denied")

    # Fetch appropriate data based on permissions
    if g.auth_context.has_permission(Permission.READ_SENSITIVE_DATA):
        cursor.execute(
            "SELECT id, username, email, phone, ssn, salary, address "
            "FROM users WHERE id = ?",
            (user_id,)
        )
    else:
        cursor.execute(
            "SELECT id, username, email, phone FROM users WHERE id = ?",
            (user_id,)
        )

    user = cursor.fetchone()
    conn.close()

    log_access('read', 'user_profile', user_id, success=True)

    return jsonify(dict(user))

@app.route('/api/organizations/<int:org_id>/users', methods=['GET'])
@require_auth
@require_permission(Permission.READ_ORG_PROFILES)
def get_org_users(org_id: int):
    """Get all users in an organization - requires org profile permission"""

    # Verify user belongs to this organization (unless super admin)
    if not g.auth_context.has_permission(Permission.ADMIN_ALL):
        if g.auth_context.org_id != org_id:
            log_access('read', 'org_users', org_id, success=False)
            abort(403, description="Cannot access other organizations")

    conn = get_db_connection()
    cursor = conn.cursor()

    cursor.execute(
        "SELECT id, username, email, department FROM users WHERE org_id = ?",
        (org_id,)
    )
    users = cursor.fetchall()
    conn.close()

    log_access('read', 'org_users', org_id, success=True)

    return jsonify({'users': [dict(u) for u in users]})

@app.errorhandler(401)
def unauthorized(e):
    return jsonify({'error': 'Unauthorized', 'message': str(e.description)}), 401

@app.errorhandler(403)
def forbidden(e):
    return jsonify({'error': 'Forbidden', 'message': str(e.description)}), 403

# Production security headers
@app.after_request
def add_security_headers(response):
    if app.config['ENV'] == 'production':
        response.headers['X-Content-Type-Options'] = 'nosniff'
        response.headers['X-Frame-Options'] = 'DENY'
        response.headers['X-XSS-Protection'] = '1; mode=block'
        response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    return response

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)
```

**Defense in Depth Layers**:

1. **Authentication Layer** - JWT validation with required claims:
```python
