	entry.ClientIP = al.SanitizeForLog(entry.ClientIP)
	entry.UserAgent = al.SanitizeForLog(entry.UserAgent)

	// Use JSON encoding which automatically escapes special characters
	jsonEntry, err := json.Marshal(entry)
	if err != nil {
		al.logger.Printf(`{"level":"ERROR","event":"log_marshal_failed","error":"failed to serialize log entry"}`)
		return
	}

