**Key Security Controls**:
- **Structured Logging (JSON)**: JSON encoding automatically escapes special characters like `\n`, `\r`, preventing log injection
- **Input Sanitization**: Control characters are stripped before logging, eliminating CRLF injection vectors
- **Length Limits**: Truncating long inputs prevents log flooding DoS attacks
- **Parameterized Fields**: User data goes into defined fields, not concatenated into message strings

In production distributed systems, log integrity is critical for incident response, compliance, and forensics. You need cryptographic integrity verification, centralized immutable storage, and real-time anomaly detection.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"regexp"
	"strings"
	"sync"
	"time"
	"unicode"

	"github.com/google/uuid"
)

// SecureLogEntry with integrity verification
type SecureLogEntry struct {
	ID           string                 `json:"id"`
	Timestamp    string                 `json:"timestamp"`
	Service      string                 `json:"service"`
	Level        string                 `json:"level"`
	Event        string                 `json:"event"`
	TraceID      string                 `json:"trace_id,omitempty"`
	SpanID       string                 `json:"span_id,omitempty"`
	Fields       map[string]interface{} `json:"fields"`
	PreviousHash string                 `json:"previous_hash"`
	Signature    string                 `json:"signature"`
}

// ProductionLogger with integrity chain
type ProductionLogger struct {
	serviceName   string
	signingKey    []byte
	previousHash  string
	mu            sync.Mutex
	logWriter     *log.Logger
	alerter       AlertingService
	anomalyDetect *AnomalyDetector
}

type AlertingService interface {
	Alert(ctx context.Context, severity, message string, fields map[string]interface{})
}

type AnomalyDetector struct {
	failedLogins     map[string]int
	failedLoginTimes map[string][]time.Time
	mu               sync.RWMutex
}

func NewAnomalyDetector() *AnomalyDetector {
	return &AnomalyDetector{
		failedLogins:     make(map[string]int),
		failedLoginTimes: make(map[string][]time.Time),
	}
}

// DetectBruteForce checks for brute force patterns
func (ad *AnomalyDetector) DetectBruteForce(clientIP string, success bool) bool {
	ad.mu.Lock()
	defer ad.mu.Unlock()

	now := time.Now()
	windowStart := now.Add(-5 * time.Minute)

	// Clean old entries
	times := ad.failedLoginTimes[clientIP]
	var recentTimes []time.Time
	for _, t := range times {
		if t.After(windowStart) {
			recentTimes = append(recentTimes, t)
		}
	}

	if !success {
		recentTimes = append(recentTimes, now)
	}
	ad.failedLoginTimes[clientIP] = recentTimes

	// Alert if more than 10 failed attempts in 5 minutes
	return len(recentTimes) > 10
}

func NewProductionLogger(serviceName string, signingKey []byte, alerter AlertingService) *ProductionLogger {
	return &ProductionLogger{
		serviceName:   serviceName,
		signingKey:    signingKey,
		previousHash:  "genesis",
		logWriter:     log.New(os.Stdout, "", 0),
		alerter:       alerter,
		anomalyDetect: NewAnomalyDetector(),
	}
}

// SanitizeInput removes injection vectors from user input
func (pl *ProductionLogger) SanitizeInput(input string) string {
	var sanitized strings.Builder

	for _, r := range input {
		// Remove all control characters
		if unicode.IsControl(r) {
			continue
		}
		// Escape potential JSON breakers
		if r == '"' || r == '\\' {
			sanitized.WriteRune('\\')
		}
		sanitized.WriteRune(r)
	}

	result := sanitized.String()

	// Truncate to prevent log flooding
	if len(result) > 256 {
		result = result[:256] + "[TRUNCATED]"
	}

	return result
}

// SanitizeFields recursively sanitizes all string values in fields
func (pl *ProductionLogger) SanitizeFields(fields map[string]interface{}) map[string]interface{} {
	sanitized := make(map[string]interface{})

	for key, value := range fields {
		// Sanitize key
		safeKey := pl.SanitizeInput(key)

		switch v := value.(type) {
		case string:
			sanitized[safeKey] = pl.SanitizeInput(v)
		case map[string]interface{}:
			sanitized[safeKey] = pl.SanitizeFields(v)
		default:
			sanitized[safeKey] = v
		}
	}

	return sanitized
}

// ComputeSignature creates HMAC signature for integrity verification
func (pl *ProductionLogger) ComputeSignature(entry *SecureLogEntry) string {
	// Create deterministic representation for signing
	data := fmt.Sprintf("%s|%s|%s|%s|%s|%s",
		entry.ID,
		entry.Timestamp,
		entry.Service,
		entry.Event,
		entry.PreviousHash,
		mustMarshal(entry.Fields),
	)

	h := hmac.New(sha256.New, pl.signingKey)
	h.Write([]byte(data))
	return hex.EncodeToString(h.Sum(nil))
}

func mustMarshal(v interface{}) string {
	data, _ := json.Marshal(v)
	return string(data)
}

// Log creates a secure, signed log entry
func (pl *ProductionLogger) Log(ctx context.Context, level, event string, fields map[string]interface{}) {
	pl.mu.Lock()
	defer pl.mu.Unlock()

	// Extract trace context if available
	traceID, _ := ctx.Value("trace_id").(string)
	spanID, _ := ctx.Value("span_id").(string)

	entry := &SecureLogEntry{
		ID:           uuid.New().String(),
		Timestamp:    time.Now().UTC().Format(time.RFC3339Nano),
		Service:      pl.serviceName,
		Level:        level,
		Event:        event,
		TraceID:      traceID,
		SpanID:       spanID,
		Fields:       pl.SanitizeFields(fields),  // Sanitize all user data
		PreviousHash: pl.previousHash,
	}

	// Sign the entry for integrity verification
	entry.Signature = pl.ComputeSignature(entry)

	// Update chain for next entry
	h := sha256.Sum256([]byte(entry.Signature))
	pl.previousHash = hex.EncodeToString(h[:])

	// Output as JSON (automatic escaping)
	jsonData, err := json.Marshal(entry)
	if err != nil {
		pl.logWriter.Printf(`{"level":"ERROR","event":"log_serialization_failed","error":"internal"}`)
		return
	}

	pl.logWriter.Println(string(jsonData))
}

// LogAuthEvent logs authentication events with anomaly detection
func (pl *ProductionLogger) LogAuthEvent(ctx context.Context, event string, username, clientIP, userAgent string, success bool) {
	// Sanitize all user-controlled inputs before creating fields map
	fields := map[string]interface{}{
		"username":   username,
		"client_ip":  clientIP,
		"user_agent": userAgent,
		"success":    success,
	}

	level := "INFO"
	if !success {
		level = "WARN"
	}

	pl.Log(ctx, level, event, fields)

	// Real-time anomaly detection
	if pl.anomalyDetect.DetectBruteForce(clientIP, success) {
		pl.Log(ctx, "CRITICAL", "brute_force_detected", map[string]interface{}{
			"client_ip": clientIP,
			"alert":     "Possible brute force attack detected",
		})

		// Send alert to security team
		if pl.alerter != nil {
			pl.alerter.Alert(ctx, "CRITICAL", "Brute force attack detected", map[string]interface{}{
				"client_ip": clientIP,
			})
		}
	}
}

// VerifyLogIntegrity verifies the integrity chain of log entries
func VerifyLogIntegrity(entries []SecureLogEntry, signingKey []byte) (bool, []string) {
	var issues []string
	expectedPreviousHash := "genesis"

	for i, entry := range entries {
		// Verify chain linkage
		if entry.PreviousHash != expectedPreviousHash {
			issues = append(issues, fmt.Sprintf("Entry %d: broken hash chain", i))
		}

		// Recompute and verify signature
		data := fmt.Sprintf("%s|%s|%s|%s|%s|%s",
			entry.ID,
			entry.Timestamp,
			entry.Service,
			entry.Event,
			entry.PreviousHash,
			mustMarshal(entry.Fields),
		)

		h := hmac.New(sha256.New, signingKey)
		h.Write([]byte(data))
		expectedSig := hex.EncodeToString(h.Sum(nil))

		if !hmac.Equal([]byte(entry.Signature), []byte(expectedSig)) {
			issues = append(issues, fmt.Sprintf("Entry %d: invalid signature (possible tampering)", i))
		}

		// Update expected hash for next entry
		nextHash := sha256.Sum256([]byte(entry.Signature))
		expectedPreviousHash = hex.EncodeToString(nextHash[:])
	}

	return len(issues) == 0, issues
}

// Example HTTP handler using production logging
func makeSecureLoginHandler(logger *ProductionLogger) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		ctx := context.WithValue(r.Context(), "trace_id", uuid.New().String())

		username := r.FormValue("username")
		password := r.FormValue("password")
		clientIP := r.RemoteAddr
		userAgent := r.Header.Get("User-Agent")

		logger.LogAuthEvent(ctx, "login_attempt", username, clientIP, userAgent, false)

		if authenticateUser(username, password) {
			logger.LogAuthEvent(ctx, "login_success", username, clientIP, userAgent, true)
			w.WriteHeader(http.StatusOK)
			w.Write([]byte("Login successful"))
		} else {
			logger.LogAuthEvent(ctx, "login_failure", username, clientIP, userAgent, false)
			http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		}
	}
}

func authenticateUser(username, password string) bool {
	return username == "admin" && password == "secure_password"
}

func main() {
