	signingKey := []byte(os.Getenv("LOG_SIGNING_KEY"))
	if len(signingKey) == 0 {
		log.Fatal("LOG_SIGNING_KEY environment variable required")
	}

	logger := NewProductionLogger("auth-service", signingKey, nil)

	http.HandleFunc("/login", makeSecureLoginHandler(logger))
	log.Fatal(http.ListenAndServe(":8080", nil))
}
